<?php namespace App\Services; use Throwable; use Illuminate\Support\Facades\Log; use Illuminate\Support\Facades\Mail; use Illuminate\Http\JsonResponse; use Symfony\Component\HttpFoundation\Response; class ExceptionHandlerService { public function handle(Throwable $exception): JsonResponse { $this->report($exception); $status = method_exists($exception, 'getStatusCode') ? $exception->getStatusCode() : Response::HTTP_INTERNAL_SERVER_ERROR; $message = $exception->getMessage() ?: 'حدث خطأ غير متوقع في النظام.'; return response()->json([ 'success' => false, 'message' => $message, 'code' => $status, 'trace' => config('app.debug') ? $exception->getTrace() : [] ], $status); } protected function report(Throwable $exception): void { Log::error($exception->getMessage(), ['exception' => $exception]); if ($this->shouldNotify($exception)) { $this->sendNotification($exception); } } protected function shouldNotify(Throwable $exception): bool { return config('app.env') === 'production'; } protected function sendNotification(Throwable $exception): void { try { $adminEmail = config('mail.admin_address'); if ($adminEmail) { Mail::raw("خطأ جديد في النظام: " . $exception->getMessage(), function ($message) use ($adminEmail) { $message->to($adminEmail)->subject('تنبيه: خطأ تقني في النظام'); }); } } catch (Throwable $e) { Log::emergency('فشل في إرسال تنبيه البريد الإلكتروني: ' . $e->getMessage()); } } }